parameters.body:
={
  "size": 0,
  "query": {
    "bool": {
      "filter": [
        {
          "range": {
            "@timestamp": {
              "gte": "{{ $fromai("gte-timestamp", "Timestamp to search after, use relative timestamps if possible, ex. now-24h", string, "now-24h") }}",
              "lt": "{{ $fromai("lt-timestamp", "Timestamp to search before, use relative timestamps if possible, ex. now", string, "now") }}",
              "time_zone": "America/Denver"
            }
          }
        },
        {
          "range": {
            "rule.level": {
              "gte": {{ $fromai("gte-rule-level", "severity level that is the lower bound of the search", number, 0) }},
                "lte": {{ $fromai("lte-rule-level", "severity level that is the upper bound of the search", number, 15) }}            }
          }
        }
      ],
      "must_not": [
        {
          "bool": {
            "should": [
              { "exists": { "field": "data.vulnerability.cve" } }
            ]
          }
        }
      ]
    }
  },
  "aggs": {
    "by_endpoint": {
      "terms": {
        "field": "agent.name",
        "size": 50,
        "order": { "_count": "desc" }
      },
      "aggs": {
        "by_finding_title": {
          "terms": {
            "field": "rule.description",
            "size": 50,
            "order": { "_count": "desc" }
          },
          "aggs": {
            "by_command": {
              "terms": {
                "field": "data.command",
                "size": 50,
                "order": { "_count": "desc" }
              }
            },
            "by_dstuser": {
              "terms": {
                "field": "data.dstuser",
                "size": 50,
                "order": { "_count": "desc" }
              }
            },
            "by_package": {
              "terms": {
                "field": "data.package",
                "size": 50,
                "order": { "_count": "desc" }
              }
            }
          }
        }
      }
    }
  }
}
